sys_rest_operation.script:
var sourceFlowId = request.body.data.flow_id;
var targetUrl = request.body.data.target_instance;
var validator = new FlowGuardValidator();
var result = validator.validate(sourceFlowId, targetUrl);
response.setContentType('application/json');
response.setBody(JSON.stringify(result));

var sourceId = request.body.data.flow_id;
var targetUrl = request.body.data.target_instance;
var userId = gs.getUserID();
var migrator = new FlowGuardMigrator();
var result = migrator.migrate(sourceId, targetUrl, userId);
response.setContentType('application/json');
response.setBody(JSON.stringify(result));

var migrationId = request.body.data.migration_id;
var migrator = new FlowGuardMigrator();
var result = migrator.rollback(migrationId);
response.setContentType('application/json');
response.setBody(JSON.stringify(result));

var flowId = request.queryParams.flow_id;
if (!flowId) { response.setBody(JSON.stringify({error: 'flow_id required'})); return; }
var migrator = new FlowGuardMigrator();
var result = migrator.diff(flowId);
response.setContentType('application/json');
response.setBody(JSON.stringify(result));

var sourceFlowId = request.body.data.flow_id;
if (!sourceFlowId) {
    response.setContentType('application/json');
    response.setBody(JSON.stringify({error: 'flow_id required'}));
    return;
}
var validator = new FlowGuardCrossEnvValidator();
var result = validator.validateAllEnvironments(sourceFlowId);
response.setContentType('application/json');
response.setBody(JSON.stringify(result));
